package com.themuffinman.app.activity.service;
import com.themuffinman.app.identity.dto.PersonalShortcutResponseDTO; import com.themuffinman.app.identity.model.AppUser; import com.themuffinman.app.identity.service.PersonalShortcutService; import org.junit.jupiter.api.Test; import java.util.List; import static org.junit.jupiter.api.Assertions.*; import static org.mockito.Mockito.*;
class WorkspaceCommandCatalogServiceTest { @Test void keepsPinnedObjectsSeparateAndReturnsOnlyRouteHandoffs(){var shortcuts=mock(PersonalShortcutService.class);var user=new AppUser();user.setId(8L);when(shortcuts.getMine(user)).thenReturn(List.of(PersonalShortcutResponseDTO.builder().targetId(7L).targetType("QUEST").title("Garden help").route("/work/quests/7").build()));var catalog=new WorkspaceCommandCatalogService(shortcuts).getCatalog(user);assertEquals("Garden help",catalog.getPersonal().getFirst().getLabel());assertTrue(catalog.getCreate().stream().allMatch(i->"CREATE_ROUTE".equals(i.getKind())));assertTrue(catalog.getVision().stream().allMatch(i->"VISION_ROUTE".equals(i.getKind())));}}
